prompt:
Write a Rust function `fn longest_common_prefix(strs: &[&str]) -> String` that finds the longest common prefix string amongst an array of strings. If there is no common prefix, return an empty string.

Include a `main` function with these tests:

fn main() {
    println!("{}", longest_common_prefix(&["flower", "flow", "flight"]));
    println!("{}", longest_common_prefix(&["dog", "racecar", "car"]));
    println!("{}", longest_common_prefix(&["interspecies", "interstellar", "interstate"]));
    println!("{}", longest_common_prefix(&["alone"]));
    println!("'{}'", longest_common_prefix(&[]));
}
